        // Hide typing and show message
        timeouts.push(
          setTimeout(() => {
            if (msg.role === "bot") {
              setIsTyping(false);
            }
            setVisibleMessages((prev) => [...prev, msg.id]);
          }, msg.delay * 1000)
        );
      });
    };

    runAnimation();

    return () => {
      timeouts.forEach(clearTimeout);
    };
  }, [key]);

